val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t> </w:t></w:r><w:r wsp:rsidR="00DC4798" wsp:rsidRPr="0093129C"><w:rPr><w:b/><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>ДЛЪЖНИ</w:t></w:r><w:r wsp:rsidR="00BB6ED5" wsp:rsidRPr="0093129C"><w:rPr><w:b/><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>ЦИ</w:t></w:r><w:r wsp:rsidR="00DC4798" wsp:rsidRPr="0093129C"><w:rPr><w:b/><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t> – </w:t></w:r><w:r wsp:rsidR="00BB6ED5" wsp:rsidRPr="0093129C"><w:rPr><w:b/><w:caps/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>(-[DLAJNICI]-)</w:t></w:r><w:r wsp:rsidR="00880883" wsp:rsidRPr="0093129C"><w:rPr><w:color w:val="000000"/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>,</w:t></w:r><w:r wsp:rsidR="00DC4798" wsp:rsidRPr="0093129C"><w:rPr><w:color w:val="000000"/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t> </w:t></w:r><w:r wsp:rsidR="00D520BE" wsp:rsidRPr="00D520BE"><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>и взех предвид следното:</w:t></w:r></w:p><w:p wsp:rsidR="002721A0" wsp:rsidRPr="0093129C" wsp:rsidRDefault="002721A0" wsp:rsidP="0093129C"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:ind w:first-line="720"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>Съгласно приетото в мотивите на т. 10 от ТР № 2/2013 г. на ВКС по </w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>тълк</w:t></w:r><w:proofErr w:type="spellEnd"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>. дело № 2/2013 г., ОСГТК, изпълнителни действия /независимо от това дали прилаганото им е поискано от взискателя или са предприети по инициатива на частен съдебен изпълнител по възлагане от взискателя/ представляват: насочването на изпълнението чрез налагането на запор или възбрана, присъединяването на кредитора, възлагането на вземане за събиране или вместо плащане, извършването на опис и оценка на вещ, назначаването на пазач, насрочването и извършването на продан и т.н. до постъпването на парични суми от </w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>проданта</w:t></w:r><w:proofErr w:type="spellEnd"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t> или на плащания от трети задължени лица. Не са изпълнителни действия образуването на изпълнително дело, изпращането и връчването на покана за доброволно изпълнение, проучването на имущественото състояние на длъжника, извършването на справки, набавянето на документи, книжа и др., назначаването на експертиза за определяне на непогасения остатък от дълга, извършването на разпределение, плащането въз основа на влязлото в сила разпределение и др.</w:t></w:r></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>Съгласно чл. 433, ал.1, т.8 ГПК изпълнителното производство се прекратява с постановление, когато взискателят не поиска извършването на изпълнителни действия в продължение на две години, с изключение на делата за издръжка. Прекратяването на изпълнителното производство на осн. чл. 433, ал.1, т.8 ГПК настъпва по силата на закона, а съдебният изпълнител може само да прогласи в постановление вече настъпилото прекратяване, когато установи осъществяването на съответните </w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>правнореевронтни</w:t></w:r><w:proofErr w:type="spellEnd"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t> факти. Смисълът на тази правна норма е свързан с това, че в изпълнителният процес взискателят има задължението със своите действия да </w:t></w:r><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>поддържа неговата </w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>висящност</w:t></w:r><w:proofErr w:type="spellEnd"/><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>, която не е обусловена само от подадената молба за образуване на изпълнителното производство и липсата на предпоставки за неговото прекратяване. Движението на изпълнителното производство зависи от взискателя, от това какви изпълнителни способи ще иска да бъдат приложени от съдебния изпълнител, от искането за повтаряне на неуспешните изпълнителни действия и прилагането на нови изпълнителни способи. С оглед на това и законодателят е счел, че липсата на активност от взискателя в хода на изпълнителното производство да отправя искане до съдебния изпълнител да извърши определени изпълнителни действия, което състояние продължава в период от две години, ще води до неговото прекратяване.</w:t></w:r></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>С оглед на гореизложеното и предвид настъпилите основания за прекратяване на производството, съдебния изпълнител дължи произнасяне и за разноските по делото.</w:t></w:r></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>Всеки един изпълнителен процес следва да приключи с рекапитулация на всички разноски направени по изпълнението, които не са били присъдени евентуално на по-ранен, междинен етап от развитието на процеса.</w:t></w:r></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:spacing w:line="276" w:line-rule="auto"/><w:jc w:val="both"/><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr></w:pPr><w:r><w:rPr><w:b-cs/><w:sz w:val="24"/><w:sz-cs w:val="24"/></w:rPr><w:t>Начислените и неплатени от взискателя такси и разноски са следните:</w:t></w:r></w:p><w:p wsp:rsidR="00C97AE2" wsp:rsidRDefault="00C97AE2" wsp:rsidP="00C97AE2"><w:pPr><w:ind w:left="-117" w:right="-648" w:first-line="425"/><w:rPr><w:b/><w:u w:val="single"/></w:rPr></w:pPr><w:r><w:rPr><w:b/><w:u w:val="single"/><w:lang w:val="EN-US"/></w:rPr><w:t>I</w:t></w:r><w:r><w:rPr><w:b/><w:u w:val="single"/></w:rPr><w:t>. ТАКСИ ПО ТТРЗЧСИ:</w:t></w:r></w:p><w:tbl><w:tblPr><w:tblW w:w="10530" w:type="dxa"/><w:tblBorders><w:top w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:left w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:bottom w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:right w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:insideH w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:insideV w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/></w:tblBorders><w:tblLook w:val="04A0"/></w:tblPr><w:tblGrid><w:gridCol w:w="1350"/><w:gridCol w:w="1260"/><w:gridCol w:w="3870"/><w:gridCol w:w="4050"/></w:tblGrid><w:tr wsp:rsidR="00C97AE2" wsp:rsidTr="00A643AB"><w:tc><w:tcPr><w:tcW w:w="1350" w:type="dxa"/><w:tcBorders><w:top w:val="single" w:sz="4" wx:bdrwidth="10" w:space="0" w:color="auto"/><w:left w:val="single" w:sz="4" wx:bdrwidth="10